  const renameMarker = ' -> ';
  const renameIdx = body.lastIndexOf(renameMarker);
  const target = renameIdx >= 0 ? body.slice(renameIdx + renameMarker.length) : body;
  const unquoted = target.replace(/^"/, '').replace(/"$/, '');
  return normalizeRepoRelativePath(unquoted);
}

