    refreshedSnapshot.repos.find((entry) => entry.id === repo.id) || refreshedBeforePush;
  const output = truncateForNotify(
    [commitOutput, pushResult.stdout, pushResult.stderr].filter(Boolean).join('\n').trim(),
    1800
  );

